#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {int key; int idx; struct Node *next;} Node;

#define MOD 1000003
Node *table[MOD];

unsigned int hash_int(int x){return ((unsigned int)x)%MOD;}

void insert(int key, int idx){
    unsigned int h = hash_int(key);
    Node *n = (Node*)malloc(sizeof(Node));
    n->key = key; n->idx = idx; n->next = table[h];
    table[h] = n;
}

int find(int key){
    unsigned int h = hash_int(key);
    for(Node *p=table[h]; p; p=p->next) if(p->key==key) return p->idx;
    return -1;
}

void clear_table(){
    for(int i=0;i<MOD;i++){
        Node *p=table[i];
        while(p){Node *tmp=p; p=p->next; free(tmp);} table[i]=NULL;
    }
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *a = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&a[i]);
        clear_table();
        int first=-1, second=-1;
        for(int i=0;i<N;i++){
            int pos = find(a[i]);
            if(pos!=-1){first=pos; second=i; break;}
            insert(a[i], i);
        }
        if(first==-1){
            printf("NO\n");
        }else{
            printf("YES\n");
            for(int i=0;i<N;i++){
                if(i==first) putchar('A');
                else if(i==second) putchar('B');
                else putchar('N');
            }
            putchar('\n');
        }
        free(a);
    }
    return 0;
}

