#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        seen = {}
        iA = iB = -1
        for i, val in enumerate(a):
            if val in seen:
                iA = seen[val]
                iB = i
                break
            seen[val] = i
        if iA == -1:
            out_lines.append("NO")
        else:
            out_lines.append("YES")
            ans = ['N'] * N
            ans[iA] = 'A'
            ans[iB] = 'B'
            out_lines.append(''.join(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

